Array.prototype.myReduce = function (callbackFn, initialValue) {
  const O = Object(this);
  const len = O.length >>> 0;
  const nextPresentIndex = (start) => {
    let i = start;
    while (i < len && !Object.prototype.hasOwnProperty.call(O, i)) i++;
    return i;
  };
  let k = 0;
  let acc;
  const initProvided = arguments.length > 1;
  if (initProvided) {
    acc = initialValue;
    k = nextPresentIndex(0);
  } else {
    k = nextPresentIndex(0);
    if (k >= len) throw new TypeError('Reduce of empty array with no initial value');
    acc = O[k++];
  }
  for (k = nextPresentIndex(k); k < len; k = nextPresentIndex(k + 1)) {
    acc = callbackFn(acc, O[k], k, O);
  }
  return acc;
};
